		}
		dispatch.Assigns[ii].GenRoute()
		newCost := dispatch.Assigns[ii].Cost
		if newCost >= 0 {
			score := (newCost - oldCost) + DIST_PENALTY*dist
			if score < bestScore {
				bestScore = score
				bestIdx = ii
				bestIsNew = false
			}
		}
		// Always rollback tentative insertion.
		dispatch.Assigns[ii].RemoveShip(total_ship + jj)
		dispatch.Assigns[ii].GenRoute()
	}

	// Evaluate a new (empty) assignment if there is room.
	if dispatch.AssignsLen < MAXASSIGNS {
		idx := dispatch.AssignsLen
		if dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
			dispatch.Assigns[idx].GenRoute()
			newCost := dispatch.Assigns[idx].Cost
			if newCost >= 0 {
				// No old cost, no distance penalty.
				score := newCost
				if score < bestScore {
					bestScore = score
					bestIdx = idx
					bestIsNew = true
				}
			}
			// Rollback tentative insertion.
			dispatch.Assigns[idx].RemoveShip(total_ship + jj)
			dispatch.Assigns[idx].GenRoute()
		}
	}

	// Apply the best candidate.
	if bestIdx >= 0 {
		if bestIsNew {
			dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestIdx].GenRoute()
			dispatch.AssignsLen = bestIdx + 1
		} else {
			dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestIdx].GenRoute()
		}
		continue
	}

	// Fallback: sequential first‑fit (safe seed‑style insertion).
	inserted := false
	for ii := 0; ii < dispatch.AssignsLen; ii++ {
		if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
			dispatch.Assigns[ii].Cost = -1 // mark as invalid (preserve behaviour)
			continue
		}
		dispatch.Assigns[ii].GenRoute()
		if dispatch.Assigns[ii].Cost >= 0 {
			inserted = true
			break
		}
		dispatch.Assigns[ii].RemoveShip(total_ship + jj)
		dispatch.Assigns[ii].GenRoute()
	}
	if !inserted && dispatch.AssignsLen < MAXASSIGNS {
		ii := dispatch.AssignsLen
		if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
			dispatch.Assigns[ii].GenRoute()
			if dispatch.Assigns[ii].Cost >= 0 {
